// ============================================================================
// getAudioFormat
// ============================================================================

describe('getAudioFormat', () => {
  it('extracts mp3 from filename', () => {
    expect(getAudioFormat('song.mp3')).toBe('mp3');
  });

  it('extracts wav from filename', () => {
    expect(getAudioFormat('narration.wav')).toBe('wav');
  });

  it('extracts ogg from filename', () => {
    expect(getAudioFormat('effect.ogg')).toBe('ogg');
  });

  it('handles uppercase extensions', () => {
    expect(getAudioFormat('file.MP3')).toBe('mp3');
  });

  it('returns null for unsupported formats', () => {
    expect(getAudioFormat('file.txt')).toBeNull();
    expect(getAudioFormat('file.exe')).toBeNull();
  });

  it('returns null for no extension', () => {
    expect(getAudioFormat('noextension')).toBeNull();
  });

  it('handles dotted filenames', () => {
    expect(getAudioFormat('my.audio.file.wav')).toBe('wav');
  });
});

// ============================================================================
