describe('isValidAudioMimeType', () => {
  it('validates audio/mpeg', () => {
    expect(isValidAudioMimeType('audio/mpeg')).toBe(true);
  });

  it('validates audio/wav', () => {
    expect(isValidAudioMimeType('audio/wav')).toBe(true);
  });

  it('validates audio/ogg', () => {
    expect(isValidAudioMimeType('audio/ogg')).toBe(true);
  });

  it('validates audio/webm', () => {
    expect(isValidAudioMimeType('audio/webm')).toBe(true);
  });

  it('rejects invalid types', () => {
    expect(isValidAudioMimeType('video/mp4')).toBe(false);
    expect(isValidAudioMimeType('text/plain')).toBe(false);
    expect(isValidAudioMimeType('')).toBe(false);
  });
});

// ============================================================================
// validateAudioFile
// ============================================================================

describe('validateAudioFile', () => {
  it('accepts valid audio file', () => {
    const result = validateAudioFile({
      name: 'test.mp3',
      size: 1024 * 1024,
      type: 'audio/mpeg',
    });
    expect(result.valid).toBe(true);
    expect(result.error).toBeUndefined();
  });

  it('rejects oversized files', () => {
    const result = validateAudioFile({
      name: 'big.mp3',
      size: MAX_AUDIO_SIZE + 1,
      type: 'audio/mpeg',
    });
    expect(result.valid).toBe(false);
    expect(result.error).toContain('grande');
  });

  it('accepts unknown mime type if extension is valid', () => {
    const result = validateAudioFile({
      name: 'test.wav',
      size: 1024,
      type: 'application/octet-stream',
    });
    expect(result.valid).toBe(true);
  });

  it('rejects unknown mime type with invalid extension', () => {
    const result = validateAudioFile({
      name: 'test.txt',
      size: 1024,
      type: 'text/plain',
    });
    expect(result.valid).toBe(false);
    expect(result.error).toContain('Formato');
  });
});

// ============================================================================
// computePeaks
// ============================================================================

describe('computePeaks', () => {
  it('computes peaks from channel data', () => {
    const data = new Float32Array([0.5, -0.8, 0.3, -0.2, 0.9, -0.1, 0.4, -0.7]);
    const peaks = computePeaks(data, 4);
    
    expect(peaks).toHaveLength(4);
    // All values should be 0-1 (normalized)
    peaks.forEach(p => {
      expect(p).toBeGreaterThanOrEqual(0);
      expect(p).toBeLessThanOrEqual(1);
    });
  });

  it('normalizes peaks to max 1', () => {
    const data = new Float32Array([0.1, -0.1, 0.1, -0.1]);
    const peaks = computePeaks(data, 2);
    
    // Max peak should be 1 after normalization
    expect(Math.max(...peaks)).toBe(1);
  });

  it('handles single sample per block', () => {
    const data = new Float32Array([0.5, 1.0]);
    const peaks = computePeaks(data, 2);
    
    expect(peaks).toHaveLength(2);
    expect(peaks[1]).toBe(1); // max value
  });

  it('handles empty data gracefully', () => {
    const data = new Float32Array(0);
    const peaks = computePeaks(data, 10);
    expect(peaks).toHaveLength(10);
  });
});

// ============================================================================
// generateDeterministicWaveform
// ============================================================================

describe('generateDeterministicWaveform', () => {
  it('generates waveform with correct length', () => {
    const waveform = generateDeterministicWaveform(12345, 50);
    expect(waveform).toHaveLength(50);
  });

  it('generates values between 0 and 1', () => {
    const waveform = generateDeterministicWaveform(42, 100);
    waveform.forEach(v => {
      expect(v).toBeGreaterThanOrEqual(0);
      expect(v).toBeLessThanOrEqual(1);
    });
  });

  it('is deterministic for same seed', () => {
    const wf1 = generateDeterministicWaveform(100, 30);
    const wf2 = generateDeterministicWaveform(100, 30);
    expect(wf1).toEqual(wf2);
  });

  it('produces different results for different seeds', () => {
    const wf1 = generateDeterministicWaveform(100, 30);
    const wf2 = generateDeterministicWaveform(200, 30);
    // Not all values should be the same
    const allSame = wf1.every((v, i) => v === wf2[i]);
    expect(allSame).toBe(false);
  });

  it('generates minimum value of 0.05', () => {
    const waveform = generateDeterministicWaveform(0, 100);
    waveform.forEach(v => {
      expect(v).toBeGreaterThanOrEqual(0.05);
    });
  });
});

// ============================================================================
// waveformPositionToTime / timeToWaveformPosition
// ============================================================================

describe('waveformPositionToTime', () => {
  it('converts 0 position to 0 time', () => {
    expect(waveformPositionToTime(0, 120)).toBe(0);
  });

  it('converts 1 position to full duration', () => {
    expect(waveformPositionToTime(1, 120)).toBe(120);
  });

  it('converts 0.5 to half duration', () => {
    expect(waveformPositionToTime(0.5, 100)).toBe(50);
  });

  it('clamps negative position', () => {
    expect(waveformPositionToTime(-0.5, 100)).toBe(0);
  });

  it('clamps position > 1', () => {
    expect(waveformPositionToTime(1.5, 100)).toBe(100);
  });
});

describe('timeToWaveformPosition', () => {
  it('converts 0 time to 0 position', () => {
    expect(timeToWaveformPosition(0, 120)).toBe(0);
  });

  it('converts duration to 1 position', () => {
    expect(timeToWaveformPosition(120, 120)).toBe(1);
  });

  it('converts mid-point correctly', () => {
    expect(timeToWaveformPosition(50, 100)).toBe(0.5);
  });

  it('returns 0 for zero duration', () => {
    expect(timeToWaveformPosition(50, 0)).toBe(0);
  });

  it('clamps time beyond duration', () => {
    expect(timeToWaveformPosition(200, 100)).toBe(1);
  });
});

